#!/usr/bin/env python3
"""
Patch script to add Cantos LVII-LXI (final batch) to data/_book1_he.json
This completes the full translation of Book I of the Ramayana
"""
import json, os, sys
if hasattr(sys.stdout, 'reconfigure'):
    sys.stdout.reconfigure(encoding='utf-8')

DATA = os.path.join(os.path.dirname(__file__), 'data')

def load():
    p = os.path.join(DATA, '_book1_he.json')
    with open(p, encoding='utf-8') as f:
        return json.load(f)

def save(cantos):
    p = os.path.join(DATA, '_book1_he.json')
    with open(p, 'w', encoding='utf-8') as f:
        json.dump(cantos, f, ensure_ascii=False, indent=1)
    print(f'✓ Saved {len(cantos)} total cantos to {p}')

